module RefModule(A, B, Cin, S, Cout);input A, B, Cin;
  output S, Cout;
  wire obf_n1, n2, n3;

  // Logic for Full Adder
  assign obf_n1 = A ^ B;    // XOR for A and B
  assign S = obf_n1 ^ Cin;  // XOR for sum with Cin
  assign n2 = A & B;    // AND for A and B
  assign n3 = obf_n1 & Cin; // AND for obf_n1 and Cin
  assign Cout = n2 | n3; // OR for Cout

endmodule
